sql:
SELECT COUNT(document_id) 
FROM application_documents 
WHERE document_status = 'Uploaded';

external_knowledge:
- 'Open' application status indicates that the course is currently accepting applications;
- 'Public' review visibility means the reviews are visible to the public;
- The number of prerequisites and faculty members can be zero if the course does not have any prerequisites or faculty members associated with it.

sql:
SELECT COUNT(DISTINCT student_id) 
FROM applications 
WHERE course_id = (SELECT course_id FROM courses WHERE course_code = 'BT101');

SELECT COUNT(DISTINCT application_id) AS total_unique_applications_paid
FROM payment_transactions
WHERE status = 'Successful';

